1	import { Controller, Get, Query } from '@nestjs/common';
2	import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
3	
4	import { FrequentlyBoughtTogetherService } from '@modules/rest/frequently-bought-together/frequently-bought-together.service';
5	
6	import { LogExecution } from '@decorators/log-execution.decorator';
7	
8	import { FrequentlyBoughtTogetherQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-query.dto';
9	import { FrequentlyBoughtTogetherResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-response.dto';
10	import { FrequentlyBoughtTogetherRootCategoriesQueryDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-query.dto';
11	import { FrequentlyBoughtTogetherRootCategoriesResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-root-categories-response.dto';
12	import { FrequentlyBoughtTogetherV2QueryDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-query.dto';
13	import { FrequentlyBoughtTogetherV2ResponseDto } from '@dto/frequently-bought-together/frequently-bought-together-v2-response.dto';
14	
15	@ApiTags('Frequently Bought Together')
16	@Controller('frequently-bought-together')
17	export class FrequentlyBoughtTogetherController {
18		constructor(
19			private readonly frequentlyBoughtTogetherService: FrequentlyBoughtTogetherService,
20		) {}
21	
22		@Get()
23		@ApiOperation({
24			summary: 'Get frequently bought together products for a style and color',
25		})
26		@ApiResponse({
27			status: 200,
28			description: 'Returns frequently bought together products',
29			type: FrequentlyBoughtTogetherResponseDto,
30		})
31		@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
32		@ApiResponse({ status: 500, description: 'Internal server error' })
33		@LogExecution({
34			paramFormatter: ([query]: [FrequentlyBoughtTogetherQueryDto]) => ({
35				styleIds: query.styleIds,
36				styleIdsCount: query.styleIds.length,
37				excludeCount: query.exclude?.length ?? 0,
38			}),
39			responseFormatter: (res: FrequentlyBoughtTogetherResponseDto) => ({
40				count: res?.frequently_bought_together?.length ?? 0,
41				fallbackUsed: res?.fallback_used ?? false,
42			}),
43		})
44		async getFrequentlyBoughtTogether(
45			@Query() query: FrequentlyBoughtTogetherQueryDto,
46		): Promise<FrequentlyBoughtTogetherResponseDto> {
47			return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogether(query);
48		}
49	
50		@Get('root-categories')
51		@ApiOperation({
52			summary:
53				'Get frequently bought together products for a style and color by root categories',
54		})
55		@ApiResponse({
56			status: 200,
57			description: 'Returns frequently bought together products by root categories',
58			type: FrequentlyBoughtTogetherRootCategoriesResponseDto,
59		})
60		@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
61		@ApiResponse({ status: 500, description: 'Internal server error' })
62		@LogExecution({
63			paramFormatter: ([query]: [FrequentlyBoughtTogetherRootCategoriesQueryDto]) => ({
64				styleIds: query.styleIds,
65				styleIdsCount: query.styleIds.length,
66				excludeCount: query.exclude?.length ?? 0,
67			}),
68			responseFormatter: (res: FrequentlyBoughtTogetherRootCategoriesResponseDto) => ({
69				count: res?.frequently_bought_together?.length ?? 0,
70				fallbackUsed: res?.fallback_used ?? false,
71			}),
72		})
73		async getFrequentlyBoughtTogetherByRootCategories(
74			@Query() query: FrequentlyBoughtTogetherRootCategoriesQueryDto,
75		): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
76			return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogetherByRootCategories(
77				query,
78			);
79		}
80	
81		@Get('v2')
82		@ApiOperation({
83			summary: 'Get frequently bought together products using co-purchase data',
84		})
85		@ApiResponse({
86			status: 200,
87			description: 'Returns co-purchased products for a style',
88			type: FrequentlyBoughtTogetherV2ResponseDto,
89		})
90		@ApiResponse({ status: 400, description: 'Bad request - invalid parameters' })
91		@ApiResponse({ status: 500, description: 'Internal server error' })
92		@LogExecution({
93			paramFormatter: ([query]: [FrequentlyBoughtTogetherV2QueryDto]) => ({
94				styleId: query.styleId,
95				limit: query.limit,
96				diversifyCategories: query.diversifyCategories,
97				favorOppositeType: query.favorOppositeType,
98			}),
99			responseFormatter: (res: FrequentlyBoughtTogetherV2ResponseDto) => ({
100				count: res?.frequently_bought_together?.length ?? 0,
101				fallbackUsed: res?.fallback_used ?? false,
102			}),
103		})
104		async getFrequentlyBoughtTogetherV2(
105			@Query() query: FrequentlyBoughtTogetherV2QueryDto,
106		): Promise<FrequentlyBoughtTogetherV2ResponseDto> {
107			return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogetherV2(query);
108		}
109	}
